"""
install_scheduling_files.py
Run from C:\\vantro:    python install_scheduling_files.py

Creates / overwrites the four scheduling files with correct UTF-8 / LF content.
No PowerShell string handling, no encoding weirdness.
"""
import base64, os, sys

FILES = {
  "lib/scheduling/resolver.ts": "",
  "app/api/admin/settings/route.ts": "",
  "app/api/admin/team/schedule/route.ts": "",
  "app/api/signin/route.ts": ""
}

def main():
    cwd = os.getcwd()
    if not cwd.lower().endswith("vantro"):
        print(f"WARNING: cwd is {cwd}")
        print("This script should be run from C:\\vantro. Continue anyway? (y/n)")
        if input().strip().lower() != "y":
            sys.exit(1)

    for rel_path, b64 in FILES.items():
        # Normalise slashes for Windows
        full_path = os.path.join(cwd, rel_path.replace("/", os.sep))
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        contents = base64.b64decode(b64).decode("utf-8")
        with open(full_path, "w", encoding="utf-8", newline="\n") as f:
            f.write(contents)
        print(f"  wrote: {rel_path}  ({len(contents)} bytes)")

    print("\nAll four files written. Next:")
    print("  npm run build")
    print("  git status")

if __name__ == "__main__":
    main()
